import sqlite3
import re
from flask import Flask, render_template, request, jsonify, g, session, redirect, url_for
import config

app = Flask(__name__)
app.config.from_object(config)

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(app.config['DATABASE'])
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def waf_filter(query_param):
    # Hardened WAF: Block common SQLi patterns
    blacklist = ["UNION", "--", "/*", "OR 1=1", "SLEEP", "BENCHMARK", "DROP", "UPDATE"]
    for word in blacklist:
        if word.lower() in str(query_param).lower():
            return False
    return True

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        # Secure login implementation
        db = get_db()
        user = db.execute('SELECT * FROM users WHERE username = ? AND password = ?', (username, password)).fetchone()
        if user:
            session['user_id'] = user['id']
            session['username'] = user['username']
            return redirect(url_for('dashboard'))
        return render_template('login.html', error="Invalid credentials")
    return render_template('login.html')

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    return render_template('dashboard.html', username=session['username'])

@app.route('/tracking')
def tracking():
    return render_template('tracking.html')

@app.route('/api/v1/shipments/search')
def api_search():
    q = request.args.get('q', '')
    db = get_db()
    # Safe search using parameterized query
    results = db.execute("SELECT * FROM shipments WHERE tracking_number LIKE ?", (f"%{q}%",)).fetchall()
    return jsonify([dict(row) for row in results])

@app.route('/api/v1/shipments/history')
def api_history():
    # Legacy endpoint for internal handhelds
    sort_col = request.args.get('sort', 'id')

    if not waf_filter(sort_col):
        return jsonify({"error": "Security filter triggered"}), 403

    db = get_db()
    try:
        # VULNERABILITY: String concatenation in ORDER BY
        query = f"SELECT id, tracking_number, status, origin_city, destination_city, weight FROM shipments ORDER BY {sort_col} ASC"
        results = db.execute(query).fetchall()
        return jsonify([dict(row) for row in results])
    except Exception as e:
        return jsonify({"error": "Internal server error"}), 500

@app.route('/admin/debug')
def debug():
    # Hidden diagnostic endpoint
    return render_template('debug.html')

@app.route('/about')
def about():
    return render_template('base.html', content="AetherFlow Logistics has been a leader in transport since 1994.")

@app.route('/contact')
def contact():
    return render_template('base.html', content="Contact us at support@aetherflow-logistics.local")

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

