{% extends 'base.html' %}
{% block body %}
<h2>Welcome, {{ username }}</h2>
<p>Active Manifests for Region: North America</p>
<div id="manifest-list">
    <p>Loading internal manifests...</p>
</div>
<script>
    // Note to dev: The legacy scanner API was moved to /api/v1/shipments/history
    // for compatibility with the RuggedScan 3000 units.
    fetch('/api/v1/shipments/history?sort=id')
        .then(r => r.json())
        .then(data => {
            const container = document.getElementById('manifest-list');
            container.innerHTML = '';
            data.forEach(item => {
                const div = document.createElement('div');
                div.className = 'shipment-card';
                div.innerHTML = `<strong>${item.tracking_number}</strong> - ${item.status}<br><small>Route: ${item.origin_city} to ${item.destination_city} (${item.weight}kg)</small>`;
                container.appendChild(div);
            });
        });
</script>
{% endblock %}

