{% extends 'base.html' %}
{% block body %}
<h2>Global Cargo Tracker</h2>
<div style="margin-bottom: 30px;">
    <input type="text" id="track-input" placeholder="Enter Tracking ID (e.g. AF-1001)" style="padding: 10px; width: 300px;">
    <button onclick="search()" class="btn">Search</button>
</div>
<div id="results"></div>
<script>
    function search() {
        const q = document.getElementById('track-input').value;
        fetch(`/api/v1/shipments/search?q=${q}`)
            .then(r => r.json())
            .then(data => {
                const res = document.getElementById('results');
                res.innerHTML = '';
                if (data.length === 0) res.innerHTML = 'No shipments found.';
                data.forEach(item => {
                    res.innerHTML += `<div class='shipment-card'><strong>${item.tracking_number}</strong>: Current Status - ${item.status}</div>`;
                });
            });
    }
</script>
{% endblock %}
